module top_module(
    input [63:0] obf_dividend,
    input [63:0] divisor,
    output reg [63:0] quotient,
    output reg [63:0] remainder
);always @(*) begin
        if (divisor == 0) begin
            quotient = 0;
            remainder = 0;
        end else begin
            quotient = obf_dividend / divisor;
            remainder = obf_dividend % divisor;
        end
    end

endmodule
